effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {

    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float luminance = dot(texColor.rgb/max(0.000001,texColor.a), luminanceWeighting);
    float p = saturate((luminance-clipLow)/(max(1.-clipHigh,clipLow+0.0001)-clipLow));
    p = pow(p,1.0/gamma);
    if(invert) p = 1.-p;
    p *= texColor.a;
    gl_FragColor = color * p;

}
